"use client";

import React from "react";
import { Hero6 } from "./hero";
import { LogoIcon } from "@/components/logo";
import { Button } from "@/components/ui/button";
import { ChevronDown } from "lucide-react";
import { cn } from "@/lib/utils";

/**
 * SLATE HEADER (Internal for Demo)
 * Replicates the provided Slate design header.
 */
function SlateHeader() {
  return (
    <header className="sticky top-10 z-40 w-full border-b border-zinc-50 bg-white/80 backdrop-blur-md dark:border-zinc-900 dark:bg-zinc-950/80">
      <div className="mx-auto flex h-20 max-w-7xl items-center justify-between px-6 sm:px-10">

        {/* Logo */}
        <div className="flex items-center gap-2.5">
          <div className="flex size-8 items-center justify-center rounded-full bg-[#03251E] text-[#BFFF70]">
            <LogoIcon className="size-5" />
          </div>
          <span className="font-heading text-2xl font-black tracking-tightest text-zinc-900 dark:text-white">
            Slate
          </span>
        </div>

        {/* Navigation */}
        <nav className="hidden items-center gap-8 md:flex">
          <a href="#" className="text-sm font-bold text-zinc-900 hover:text-zinc-600 transition-colors dark:text-zinc-400">Home</a>
          <div className="flex items-center gap-1 cursor-pointer group text-sm font-bold text-zinc-900 transition-colors dark:text-zinc-400">
            <span>Product</span>
            <ChevronDown className="size-4 transition-transform group-hover:rotate-180" />
          </div>
          <a href="#" className="text-sm font-bold text-zinc-900 hover:text-zinc-600 transition-colors dark:text-zinc-400">Pricing</a>
          <a href="#" className="text-sm font-bold text-zinc-900 hover:text-zinc-600 transition-colors dark:text-zinc-400">Contact</a>
        </nav>

        {/* Auth Actions */}
        <div className="flex items-center gap-4">
          <Button variant="outline" className="hidden border-zinc-200 rounded-full px-8 font-black text-zinc-900 hover:bg-zinc-50 sm:inline-flex dark:border-zinc-800 dark:text-white">
            Sign in
          </Button>
          <Button className="h-10 rounded-full bg-[#03251E] px-8 font-black text-white hover:bg-zinc-800 transition-all hover:scale-[1.02]">
            Sign up for free
          </Button>
        </div>
      </div>
    </header>
  );
}

/**
 * HERO 6 PAGE ENTRY
 * Demonstrates the full "Slate Masterpiece" experience.
 */
export default function Hero6Page() {
  return (
    <div className="w-full">
      <SlateHeader />
      <main>
        <Hero6 />
      </main>
    </div>
  );
}

"use client";

import { motion } from "motion/react";
import { Button } from "@/components/ui/button";
import { ArrowRight, Box, CircleDot, Mail, Share2, Sparkles, Zap } from "lucide-react";
import { cn } from "@/lib/utils";
import { 
  BalanceProgressBarCard, 
  IncomeChartCard, 
  MemberGrowthCard, 
  RevenueMetricCard 
} from "./cards";

/**
 * HERO 6: THE SLATE MASTERPIECE
 * Pixel-perfect SaaS Hero with floating UI mockups, dot grids, and SVG path tracing.
 */
export function Hero6() {
  return (
    <section className="relative min-h-screen w-full overflow-hidden bg-white dark:bg-zinc-950 font-sans selection:bg-[#BFFF70]/30 transition-colors duration-500">

      {/* 1. Header Banner & Infrastructure */}
      <div className="absolute top-0 z-50 flex h-10 w-full items-center justify-between bg-[#03251E] px-6 text-[11px] font-bold text-white uppercase tracking-widest sm:px-10">
        <div className="flex items-center gap-2">
           <CircleDot className="size-3 animate-pulse text-[#BFFF70]" />
           <span>The banner is to inform the visitors of an important message</span>
        </div>
        <div className="hidden items-center gap-4 sm:flex">
           <Share2 className="size-3.5 cursor-pointer hover:text-[#BFFF70] transition-colors" />
           <Box className="size-3.5 cursor-pointer hover:text-[#BFFF70] transition-colors" />
           <Sparkles className="size-3.5 cursor-pointer hover:text-[#BFFF70] transition-colors" />
        </div>
      </div>

      {/* 2. Generative Background Infrastructure (Dot Grid) */}
      <div className="absolute inset-0 z-0 opacity-40">
        <div 
          className="h-full w-full"
          style={{
            backgroundImage: "radial-gradient(#03251E 0.5px, transparent 0.5px)",
            backgroundSize: "32px 32px"
          }}
        />
      </div>

      <div className="relative z-10 mx-auto flex min-h-screen max-w-7xl flex-col items-center justify-center px-6 pt-20">

        {/* 3. Floating UI Mockups (Neural Positions) */}
        <div className="pointer-events-none absolute inset-0 hidden lg:block">
          {/* Left Side Group */}
          <motion.div 
             initial={{ opacity: 0, x: -100, y: 20 }}
             animate={{ opacity: 1, x: 0, y: 0 }}
             transition={{ duration: 1, delay: 0.2, ease: "circOut" }}
             className="absolute top-[28%] left-[2%] pointer-events-auto"
          >
            <IncomeChartCard />
          </motion.div>
          <motion.div 
             initial={{ opacity: 0, x: -80, y: 40 }}
             animate={{ opacity: 1, x: 0, y: 0 }}
             transition={{ duration: 1, delay: 0.4, ease: "circOut" }}
             className="absolute top-[52%] left-[4%] pointer-events-auto"
          >
            <MemberGrowthCard />
          </motion.div>

          {/* Right Side Group */}
          <motion.div 
             initial={{ opacity: 0, x: 100, y: -20 }}
             animate={{ opacity: 1, x: 0, y: 0 }}
             transition={{ duration: 1, delay: 0.3, ease: "circOut" }}
             className="absolute top-[26%] right-[3%] pointer-events-auto"
          >
            <RevenueMetricCard />
          </motion.div>
          <motion.div 
             initial={{ opacity: 0, x: 80, y: -40 }}
             animate={{ opacity: 1, x: 0, y: 0 }}
             transition={{ duration: 1, delay: 0.5, ease: "circOut" }}
             className="absolute top-[50%] right-[3%] pointer-events-auto"
          >
            <BalanceProgressBarCard />
          </motion.div>
        </div>

        {/* 4. Strategic Content Stack */}
        <div className="text-center">
          <motion.span
            initial={{ opacity: 0, y: 10 }}
            animate={{ opacity: 1, y: 0 }}
            className="mb-4 inline-block text-[14px] font-bold text-zinc-900 dark:text-emerald-400"
          >
            55,000+ Business Trust
          </motion.span>

          <h1 className="relative max-w-4xl font-heading text-[clamp(2.5rem,8vw,5.5rem)] font-bold leading-[0.95] tracking-tightest text-zinc-900 dark:text-white">
            <motion.span
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ duration: 0.8 }}
              className="inline-block"
            >
              Deliver&nbsp;
            </motion.span>
            <motion.span 
              initial={{ scale: 0.95, opacity: 0 }}
              animate={{ scale: 1, opacity: 1 }}
              transition={{ duration: 1, delay: 0.5 }}
              className="relative mx-1 inline-block rounded-xl bg-[#BFFF70] px-3 py-1 text-[#03251E] shadow-sm"
            >
              the Perfect
            </motion.span>
            <br />
            <motion.span
               initial={{ opacity: 0, y: 20 }}
               animate={{ opacity: 1, y: 0 }}
               transition={{ duration: 0.8, delay: 0.2 }}
               className="relative inline-block"
            >
              solution
              {/* 5. SVG Path Tracing (The "Hand-Drawn" look) */}
              <svg 
                className="absolute -bottom-2 left-0 h-4 w-full text-zinc-900/10 dark:text-emerald-400/20"
                viewBox="0 0 200 20"
                fill="none"
              >
                <motion.path
                  initial={{ pathLength: 0 }}
                  animate={{ pathLength: 1 }}
                  transition={{ duration: 1.5, delay: 1, ease: "easeInOut" }}
                  d="M 5 15 Q 100 0, 195 15"
                  stroke="currentColor"
                  strokeWidth="3"
                  strokeLinecap="round"
                />
              </svg>
            </motion.span>
            <motion.span
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ duration: 0.8, delay: 0.3 }}
              className="inline-block"
            >
              &nbsp;for your client now
            </motion.span>
          </h1>

          <motion.p
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.8, delay: 0.4 }}
            className="mx-auto mt-8 max-w-xl text-balance text-lg font-medium text-zinc-500 leading-relaxed dark:text-zinc-400"
          >
            Lorem ipsum dolor sit amet, consectetur adipiscing elit. <br className="hidden sm:block" />
            Phasellus sodales leo id commodo ornare. 
          </motion.p>

          {/* 6. Elite SaaS Input CTA */}
          <motion.div
             initial={{ opacity: 0, y: 20 }}
             animate={{ opacity: 1, y: 0 }}
             transition={{ duration: 0.8, delay: 0.6 }}
             className="mx-auto mt-12 flex max-w-lg items-center justify-between rounded-full border border-zinc-200 bg-white/50 p-1.5 shadow-xl backdrop-blur-md dark:border-zinc-800 dark:bg-zinc-900/50"
          >
            <div className="flex flex-1 items-center gap-3 px-4">
              <Mail className="size-4 text-zinc-400" />
              <input 
                type="email" 
                placeholder="Enter your mail address" 
                className="w-full bg-transparent text-sm font-medium outline-none placeholder:text-zinc-400"
              />
            </div>
            <Button size="lg" className="h-12 rounded-full bg-[#BFFF70] font-black text-[#03251E] hover:bg-[#AEEB60] transition-all hover:scale-[1.02]">
              Get Started
            </Button>
          </motion.div>

          <motion.span
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            transition={{ delay: 1.2 }}
            className="mt-6 inline-block text-[11px] font-bold text-zinc-400 uppercase tracking-widest"
          >
            This template <span className="mx-1">✥</span> Free to get started
          </motion.span>
        </div>
      </div>

      {/* 7. Service Highlight Footer */}
      <div className="border-t border-zinc-100 bg-white px-10 py-12 dark:border-zinc-800 dark:bg-zinc-950">
        <div className="mx-auto grid max-w-7xl grid-cols-1 gap-12 md:grid-cols-3">
          {[
            { icon: Box, text: "Lorem ipsum dolor sit amet, consectetur." },
            { icon: Sparkles, text: "Lorem ipsum dolor sit amet, consectetur." },
            { icon: Zap, text: "Lorem ipsum dolor sit amet, consectetur." }
          ].map((item, i) => (
            <motion.div 
              key={i} 
              initial={{ opacity: 0, y: 20 }}
              whileInView={{ opacity: 1, y: 0 }}
              transition={{ delay: i * 0.1 }}
              viewport={{ once: true }}
              className="flex items-center gap-6"
            >
              <div className="flex size-14 shrink-0 items-center justify-center rounded-full bg-zinc-50 dark:bg-zinc-900 border border-zinc-100 dark:border-zinc-800">
                <item.icon className="size-6 text-zinc-900 dark:text-emerald-400" />
              </div>
              <p className="text-sm font-bold text-zinc-900 dark:text-zinc-400 leading-relaxed">
                {item.text}
              </p>
            </motion.div>
          ))}
        </div>
      </div>
    </section>
  );
}

"use client";

import { motion } from "motion/react";
import { ArrowUpRight, DollarSign, TrendingUp, Users } from "lucide-react";
import { cn } from "@/lib/utils";

/**
 * REVENUE METRIC CARD (Right Top)
 * Features "Total Revenue" title, status pill, and high-fidelity currency display.
 */
export function RevenueMetricCard({ className }: { className?: string }) {
  return (
    <motion.div
      whileHover={{ y: -5, transition: { duration: 0.2 } }}
      className={cn(
        "flex flex-col gap-4 rounded-2xl border border-zinc-100 bg-white p-6 shadow-xl dark:border-zinc-800 dark:bg-zinc-950",
        className
      )}
    >
      <div className="flex items-center justify-between">
        <span className="text-[13px] font-semibold text-zinc-500 uppercase tracking-wide">Total Revenue</span>
        <div className="flex size-6 items-center justify-center rounded-full bg-[#BFFF70]/10 text-[#54A000]">
           <ArrowUpRight className="size-3.5" />
        </div>
      </div>
      <div className="flex items-center gap-3">
        <div className="flex size-12 items-center justify-center rounded-full bg-[#BFFF70] text-[#03251E]">
          <DollarSign className="size-6" />
        </div>
        <div className="flex flex-col">
          <span className="text-3xl font-bold tracking-tight text-zinc-900 dark:text-white">4.32k</span>
          <span className="text-[12px] font-medium text-emerald-600">+12.5% from last month</span>
        </div>
      </div>
    </motion.div>
  );
}

/**
 * INCOME CHART CARD (Left Top)
 * Features "Income & Expenses" title and a stylized high-fidelity mockup chart.
 */
export function IncomeChartCard({ className }: { className?: string }) {
  return (
    <motion.div
      whileHover={{ y: -5, transition: { duration: 0.2 } }}
      className={cn(
        "flex flex-col gap-6 rounded-2xl border border-zinc-100 bg-white p-6 shadow-xl dark:border-zinc-800 dark:bg-zinc-950",
        "w-[280px]",
        className
      )}
    >
      <div className="flex items-center justify-between border-b border-zinc-50 pb-4 dark:border-zinc-900">
        <span className="text-[13px] font-bold text-zinc-900 dark:text-white">Income & Expenses</span>
        <button className="text-[12px] font-bold text-zinc-400 hover:text-zinc-600 transition-colors">7 Days</button>
      </div>

      {/* Stylized Chart Mockup */}
      <div className="relative h-32 w-full pt-4">
        {/* Mock Chart SVG */}
        <svg className="h-full w-full" viewBox="0 0 200 80">
          <path
            d="M 10 70 Q 30 20, 50 60 T 90 20 T 130 50 T 170 10 T 190 40"
            fill="none"
            stroke="#03251E"
            strokeWidth="3.5"
            strokeLinecap="round"
            className="opacity-90 dark:stroke-emerald-400"
          />
          <path
            d="M 10 70 Q 30 20, 50 60 T 90 20 T 130 50 T 170 10 T 190 40 L 190 80 L 10 80 Z"
            fill="url(#chart-gradient)"
            className="opacity-10"
          />
          <defs>
            <linearGradient id="chart-gradient" x1="0" x2="0" y1="0" y2="1">
              <stop offset="0%" stopColor="#BFFF70" />
              <stop offset="100%" stopColor="transparent" />
            </linearGradient>
          </defs>
          <circle cx="170" cy="10" r="4" fill="#BFFF70" className="animate-pulse shadow-glow" />
        </svg>

        {/* Floating Tooltip */}
        <div className="absolute top-0 right-4 rounded bg-[#BFFF70] px-2 py-1 text-[10px] font-bold text-[#03251E] shadow-sm">
          $2,890
        </div>
      </div>
    </motion.div>
  );
}

/**
 * BALANCE PROGRESS CARD (Right Bottom)
 * Features "Balance" title, numeric amount, and custom progress bar with Pine accent.
 */
export function BalanceProgressBarCard({ className }: { className?: string }) {
  return (
    <motion.div
      whileHover={{ y: -5, transition: { duration: 0.2 } }}
      className={cn(
        "flex flex-col gap-5 rounded-2xl border border-zinc-100 bg-white p-6 shadow-xl dark:border-zinc-800 dark:bg-zinc-950",
        "w-[260px]",
        className
      )}
    >
      <div className="flex items-center justify-between">
        <span className="text-[13px] font-bold text-zinc-900 dark:text-white">Balance</span>
        <span className="rounded-full bg-zinc-900 px-3 py-1 text-[10px] font-bold text-white uppercase tracking-wider">Reserved</span>
      </div>
      <div className="flex flex-col gap-1">
        <span className="text-2xl font-black text-zinc-900 dark:text-white">$60,124.00</span>
        <div className="mt-2 flex items-center justify-between">
          <div className="flex items-center gap-1.5 text-[10px] font-black text-zinc-400 uppercase tracking-widest">
            <div className="size-1.5 rounded-full bg-[#BFFF70]" />
            Pine Account
          </div>
          <span className="text-[10px] font-black text-zinc-900 dark:text-emerald-400">75%</span>
        </div>
        <div className="relative mt-1 h-1.5 w-full overflow-hidden rounded-full bg-zinc-50 dark:bg-zinc-900">
          <motion.div 
            initial={{ width: 0 }}
            animate={{ width: "75%" }}
            transition={{ duration: 1, delay: 0.5, ease: "circOut" }}
            className="h-full bg-[#BFFF70] shadow-[0_0_10px_rgba(191,255,112,0.4)]" 
          />
        </div>
      </div>
    </motion.div>
  );
}

/**
 * MEMBER GROWTH CARD (Left Bottom)
 * Features numeric metric, progress badge, and descriptive footer.
 */
export function MemberGrowthCard({ className }: { className?: string }) {
  return (
    <motion.div
      whileHover={{ y: -5, transition: { duration: 0.2 } }}
      className={cn(
        "flex flex-col gap-4 rounded-2xl border border-zinc-100 bg-white p-6 shadow-xl dark:border-zinc-800 dark:bg-zinc-950",
        className
      )}
    >
      <div className="flex items-center gap-4">
        <div className="flex flex-col">
          <span className="text-3xl font-black text-zinc-900 dark:text-white">75%</span>
          <span className="text-[12px] font-medium text-zinc-500">Member Growth</span>
        </div>
        <div className="flex h-12 items-center justify-center rounded-xl bg-zinc-900 px-4 text-white hover:bg-zinc-800 transition-colors cursor-pointer">
           <span className="text-[12px] font-bold">Details</span>
        </div>
      </div>
    </motion.div>
  );
}
